// v5.10.x strings (token-aware budgeting, backend retry, self-test, deployment presets, escalation consent, privacy).
$string['settings:backend_context_tokens'] = 'Backend-kontekstvindue (tokens)';
$string['settings:backend_context_tokens_desc'] = 'Den maksimale kontekstlængde (max_model_len) for din AI-backend, i tokens. Sæt til 0 for hostede modeller med et stort vindue (ingen begrænsning). Når den sættes over 0 (for eksempel 8192 på en selvhostet vLLM-backend), reducerer SOLA tegnbudgettet for systemprompten ovenfor, så prompten plus reserveret output og samtalehistorik passer ind i vinduet, selv på token-tætte sprog. Se wiki-siden Deployment Sizing for, hvordan dette hænger sammen med samtidige brugere.';
$string['settings:backend_retry_attempts'] = 'Backend-genforsøg';
$string['settings:backend_retry_attempts_desc'] = 'Hvor mange gange en forbigående backend-fejl (HTTP 429 eller 503) skal forsøges igen, før der vises en fejl til den studerende. Genforsøg sker kun, før noget svartekst er blevet streamet, så output bliver aldrig duplikeret. Rettet mod små selvhostede backends, der afviser anmodninger under belastning. Sæt til 0 for at deaktivere. Standard 2.';
$string['settings:backend_retry_max_wait'] = 'Maksimal ventetid for backend-genforsøg (sekunder)';
$string['settings:backend_retry_max_wait_desc'] = 'Øvre grænse, i sekunder, for hvor længe en Retry-After-header fra backenden skal respekteres, før der forsøges igen. Når backenden ikke sender nogen Retry-After, bruger SOLA i stedet en kort eksponentiel backoff. Standard 5.';
$string['prompt:truncation_hint'] = 'BEMÆRK: Hele kursusindholdet kunne ikke søges denne tur på grund af længdebegrænsninger. Hvis den studerende spørger om noget, du ikke kan finde i det leverede indhold, så sig, at du ikke kunne søge i hele kurset, og foreslå, at de åbner den specifikke side eller aktivitet, hvor emnet er dækket, i stedet for at fastslå, at det mangler i kurset.';
$string['selftest:title'] = 'Backend-selvtest';
$string['selftest:intro'] = 'Kør et live-tjek af din konfigurerede AI-backend: en lille chat-rundtur, automatisk registrering af kontekstvinduet (max_model_len) og en sammenligning med din indstilling for backend-kontekstvindue, gulvet for systemprompt-budgettet og (når RAG er slået til) en embedding-rundtur. Netværkskald køres kun, når du trykker på Kør.';
$string['selftest:run'] = 'Kør backend-selvtest';
$string['selftest:check'] = 'Tjek';
$string['selftest:status'] = 'Status';
$string['selftest:detail'] = 'Detalje';
$string['selftest:link'] = 'Side for backend-selvtest';
$string['selftest:link_desc'] = 'Åbn siden <a href="{$a}">Backend-selvtest</a> for at verificere, at din AI-backend virker og er korrekt dimensioneret. Nyttig lige efter konfiguration af en selvhostet backend.';
$string['profile:title'] = 'Forudindstillinger for udrulning';
$string['profile:intro'] = 'Anvend et anbefalet bundt af indstillinger til din udrulningstype. Værdierne skrives ind i de almindelige plugin-indstillinger og forbliver individuelt redigerbare bagefter. Anvendelse af en forudindstilling overskriver de anførte indstillinger.';
