$string['profile:apply_hosted_large'] = 'Anvend standarder for hostet stor kontekst';
$string['profile:applied'] = 'Forudindstillingen {$a} er anvendt. Værdierne er nu i dine plugin-indstillinger.';
$string['profile:unknown'] = 'Ukendt udrulningsforudindstilling.';
$string['profile:link'] = 'Side for udrulningsforudindstillinger';
$string['profile:link_desc'] = 'Åbn siden <a href="{$a}">Forudindstillinger for udrulning</a> for at anvende et anbefalet bundt af indstillinger til en hostet eller selvhostet backend.';
$string['settings:zendesk_require_consent'] = 'Kræv samtykke før eskalering til support';
$string['settings:zendesk_require_consent_desc'] = 'Når den er slået til (anbefales), eskalerer SOLA kun en samtale til Zendesk-supportskranken, efter at den lærende har accepteret samtykkemeddelelsen ved første kørsel, som oplyser, at det at anmode om menneskelig hjælp deler samtalen (inklusive navn og e-mail) med supporten. Slå kun dette fra, hvis du indhenter dette samtykke på anden vis; når det er slået fra, sendes eskaleringer straks. Har ingen effekt, medmindre Zendesk-eskalering er aktiveret.';
$string['chat:escalation_needs_consent'] = 'Det ser ud til, at dette kræver et medlem af vores supportteam. For at videregive det til dem ville jeg skulle dele denne samtale, inklusive dit navn og e-mail, med supportskranken. Du har ikke accepteret det endnu, så jeg har ikke sendt noget. Hvis du ønsker menneskelig hjælp, så accepter venligst meddelelsen om datadeling for denne assistent og spørg igen, eller kontakt supporten direkte.';
$string['privacy:metadata:email_optout'] = 'Fravalgspræferencer for e-mail pr. modtager (hvilke e-mailtyper en modtager har afmeldt sig).';
$string['privacy:metadata:email_optout:email'] = 'Modtagerens e-mailadresse, som fravalget gælder for.';
$string['privacy:metadata:email_optout:optout_type'] = 'Den e-mailtype, modtageren har fravalgt.';
$string['privacy:metadata:email_optout:userid'] = 'Den Moodle-bruger, fravalget tilhører, når det er kendt.';
$string['chat:consent_scroll_hint'] = 'Rul venligst ned til bunden for at læse hele meddelelsen, før du fortsætter.';
$string['settings:rag_min_similarity'] = 'Minimal relevans (cosine)';
$string['settings:rag_min_similarity_desc'] = 'Udelad hentede tekststykker, hvis cosine-lighed med spørgsmålet er under denne værdi, så et spørgsmål uden for emnet eller med få oplysninger indsætter færre (eller nul) passager i stedet for altid at fylde op til Top-K med svage match. Interval 0 til 1; 0 deaktiverer porten. Den rigtige værdi afhænger af embedding-modellen: 0.25 passer til text-embedding-3-small. Hæv den for at være strengere (mindre, mere emnerelevant kontekst), sænk den for at være mere tilladende.';
$string['settings:rag_currentpage_boost'] = 'Forstærkning af aktuel side';
$string['settings:rag_currentpage_boost_desc'] = 'En lille bonus, der lægges til relevansscoren for tekststykker fra den side, den lærende aktuelt ser på, så spørgsmål som "forklar dette" foretrækker den synlige side, når scorerne er tæt på hinanden. Kun rækkefølge: det tvinger ikke et irrelevant sidetekststykke forbi porten for minimal relevans. Sæt til 0 for at deaktivere.';
$string['settings:history_mode'] = 'Tilstand for historikvalg';
$string['settings:history_mode_desc'] = 'Hvordan tidligere samtaleomgange vælges, før de sendes til modellen. <strong>Semantic</strong> beholder kun de nylige omgange, der er relevante for det aktuelle spørgsmål (og altid den seneste udveksling), så en forældet, emnefremmed tidligere omgang ikke oppuster omkostningen eller trækker svaret på afveje; den foretager ét ekstra embedding-kald pr. besked. <strong>Recency</strong> beholder de sidste "Max Conversation History" par uanset relevans (den mangeårige adfærd, ingen ekstra kald). Hvis embedding ikke er tilgængelig, falder semantisk tilstand automatisk tilbage til recency.';
$string['settings:history_mode_semantic'] = 'Semantic (relevante nylige omgange)';
$string['settings:history_mode_recency'] = 'Recency (sidste N par)';
$string['settings:history_semantic_minscore'] = 'Relevansgulv for historik (cosine)';
$string['settings:history_semantic_minscore_desc'] = 'I semantisk historiktilstand beholdes en tidligere omgang kun, hvis dens lighed med det aktuelle spørgsmål er mindst denne værdi (den seneste udveksling beholdes altid). Interval 0 til 1; modelafhængig. Hæv for at være strengere (mindre historik), sænk for at beholde mere.';
$string['settings:history_candidates'] = 'Kandidatvindue for historik';
$string['settings:history_candidates_desc'] = 'I semantisk historiktilstand scores kun så mange af de nyeste par for relevans (en omkostningsgrænse). Par, der er ældre end dette vindue, sendes ikke. Hold denne værdi på eller over "Max Conversation History".';

// v5.11.0 - v6.2.0 strings (added 2026-06-10).
$string['settings:embed_provider_voyage'] = 'Voyage AI (voyage-3.5 — anbefalet; +4 MTEB ift. OpenAI 3-small, 4× kontekst, flersproget)';
$string['settings:rerank_heading'] = 'RAG: To-trins hentning (reranking)';
$string['settings:rerank_heading_desc'] = 'Valgfri anden hentningsfase: kosinuslighed vælger top-N kandidatudsnit (standard 50), derefter scorer en cross-encoder-reranker hvert (forespørgsel, udsnit)-par, og de bedste top-K indgår i prompten. Slået fra som standard; falder tilbage til enkeltfase-kosinus, hvis rerankeren ikke er konfigureret eller fejler.';
$string['settings:rerank_enabled'] = 'To-trins hentning (Voyage rerank-2.5)';
$string['settings:rerank_enabled_desc'] = 'Når aktiveret bliver RAG-hentning to-trins: kosinuslighed returnerer top-N kandidater (standard 50), derefter scorer Voyage rerank-2.5 cross-encoder dem enkeltvis, og top-K indgår i prompten. Publicerede forbedringer: +15 Recall@10 enterprise, +39 % NDCG BEIR. ~$0,05/MTok fakturering. Kræver <code>rerank_apikey</code> nedenfor; falder elegant tilbage til enkeltfase-kosinus, hvis reranking fejler eller ikke er konfigureret.';
$string['settings:rerank_apikey'] = 'Rerank API-nøgle';
$string['settings:rerank_apikey_desc'] = 'Voyage AI API-nøgle til rerank-2.5. Lad feltet stå tomt for at genbruge Embedding API-nøglen ovenfor (typiske Voyage-installationer deler én nøgle på tværs af embed + rerank).';
$string['settings:rerank_model'] = 'Rerankmodel';
$string['settings:rerank_model_desc'] = 'Standard <code>rerank-2.5</code>. Nyere Voyage rerank-modeller kan angives her.';
$string['settings:rerank_apibaseurl'] = 'Rerank API-basis-URL';
$string['settings:rerank_apibaseurl_desc'] = 'Tilsidesæt Voyage rerank-basis-URL. Lad feltet stå tomt for at bruge Embedding API-basis-URL ovenfor eller Voyage-standardadressen (<code>https://api.voyageai.com/v1</code>).';
$string['settings:rerank_candidates'] = 'Rerankkandidat-vindue';
$string['settings:rerank_candidates_desc'] = 'Hvor mange kosinus-top-N-kandidater der indgår i rerankfasen. Standard 50. Større vinduer giver rerankeren mere materiale at arbejde med til en lille ekstraomkostning (~10.000 tokens pr. rerankoperation).';
$string['settings:stt_selfhosted_heading'] = 'Selvhostet transskription (Whisper)';
$string['settings:stt_selfhosted_heading_desc'] = 'Kør tale-til-tekst på eget hardware uden afregning pr. minut. Peg SOLA mod enhver OpenAI-kompatibel transskriptionsserver: Docker <code>whisper-server</code>, <code>speaches</code> (faster-whisper) eller <code>whisper.cpp</code>-server. Når en server-URL angives her, bliver den standardstien for STT; vælg en betalt udbyder under Aktiv STT-udbyder ovenfor for at tilsidesætte. Hvis serveren er på et privat netværk eller almindelig http, skal du også tilføje dens vært til SSRF-tillidte slutpunkter i Sikkerhedssektionen.';
$string['settings:stt_selfhosted_url'] = 'Selvhostet STT-server-URL';
$string['settings:stt_selfhosted_url_desc'] = 'Basis-URL for den OpenAI-kompatible transskriptionsserver, f.eks. <code>http://10.0.0.5:8000</code>. SOLA tilføjer automatisk <code>/v1/audio/transcriptions</code>; en fuld slutpunktssti accepteres også. Lad feltet stå tomt for at deaktivere selvhostet STT.';
$string['settings:stt_selfhosted_model'] = 'Selvhostet STT-model';
$string['settings:stt_selfhosted_model_desc'] = 'Modelnavn sendt til serveren, der svarer til den Whisper-model, den har indlæst — f.eks. <code>Systran/faster-whisper-small</code> til speaches eller <code>large-v3</code>. Lad feltet stå tomt for at sende <code>whisper-1</code>, som de fleste selvhostede servere accepterer eller ignorerer.';
$string['settings:stt_selfhosted_apikey'] = 'Selvhostet STT API-nøgle';
$string['settings:stt_selfhosted_apikey_desc'] = 'Valgfrit. De fleste selvhostede servere er nøglefrie bag et betroet netværk; angiv kun dette, hvis din server kræver et Bearer-token.';
