$string['settings:prompt_proportions_heading'] = 'Promptsektionsproportioner (v5.6.0)';
$string['settings:prompt_proportions_heading_desc'] = 'Fordel systempromptbudgettet på fire grupper: sikkerhed + identitet, kursusstruktur, kursusindhold og aktuel side. Vægtene er procenttal med summen 100. Empirisk tilpassede standarder (10 / 10 / 40 / 40) stammer fra v5.6.0-vægtjusteringsbenchmark; det tomme tekstfelt bruger disse standarder. Den automatiske forstærkning justerer fordelingen pr. omgang afhængigt af, om en specifik side er i omfang.';
$string['settings:prompt_section_weights'] = 'Basisafsnitsvægte (JSON)';
$string['settings:prompt_section_weights_desc'] = 'Valgfrit JSON-objekt, der tilknytter en procentdel til hvert segment. Lad feltet stå tomt for at bruge de benchmarked standardværdier (10 / 10 / 40 / 40). Eksempel: <code>{"safety_identity": 10, "course_structure": 10, "course_content": 40, "current_page": 40}</code>. Vægtene skal give en sum på 100 (±5 %). <code>safety_identity</code> har et gulv på 10 %, så jailbreak-modstand og outputformatmarkører altid lander fuldt ud. <code>current_page + course_content</code> skal udgøre mindst 40 %, så modellen har væsentligt materiale at forankre sig i. Værdier uden for området falder stille tilbage til de benchmarked standarder; administratorer bør validere ved at tjekke promptfejlfindingsloggen efter lagring.';
$string['settings:prompt_context_boost_mode'] = 'Kontekstforstærkningstilstand';
$string['settings:prompt_context_boost_mode_desc'] = 'Automatisk justering, der skifter vægt mod det aktuelle afsnit, når en specifik side er i omfang, og mod kursusindhold, når ingen side er valgt. <strong>page_focus</strong> (standard) skifter ca. 15 vægtpoint. <strong>aggressive</strong> skifter 25 point og er bedst, når kursister konsekvent stiller sidespecifikke spørgsmål. <strong>off</strong> deaktiverer forstærkningen; administratorsatte basisvægte gælder ved hver omgang uanset sidekontekst.';
$string['settings:prompt_context_boost_off'] = 'Fra (brug basisvægte ved hver omgang)';
$string['settings:prompt_context_boost_page_focus'] = 'Sidefokus (standard, ~15 points skift)';
$string['settings:prompt_context_boost_aggressive'] = 'Aggressiv (~25 points skift)';
$string['settings:prompt_section_weights_coach'] = 'Coach-tilstandstilsidesættelse (JSON, valgfrit)';
$string['settings:prompt_section_weights_coach_desc'] = 'Valgfrit JSON-objekt, der tilsidesætter basisafsnitsværgtene specifikt under bedømt quizcoachtilstand (når <code>quizmode=coach</code>). Nyttigt til at tvinge en større <code>current_page</code>-tildeling under quizzer uden at påvirke normal chat. Lad feltet stå tomt for at arve basisvægtene. Samme valideringsregler som for basisindstillingen.';
$string['prompt_debug_view:title'] = 'Promptfejlfindingslogviser';
$string['prompt_debug_view:subtitle'] = 'Den samlede systemprompt pr. omgang + pr. afsnit opdeling + samtalehistorik + aktuel brugerbesked + vedhæftede metadata, præcis som modellen modtog dem. Brug dette til at verificere, om et afsnit som Aktuelt sideindhold faktisk landede i prompten, og til at fejlfinde svarskvalitetsproblemer uden SSH til serveren.';
$string['prompt_debug_view:disabled'] = 'Promptfejlfindingslogning er i øjeblikket SLÅET FRA. Ingen nye poster skrives, før den aktiveres.';
$string['prompt_debug_view:enable_link'] = 'Åbn plug-in-indstillinger for at aktivere „Log samlet systemprompt til fil".';
