$string['settings:mastery_classifier_provider'] = 'Klassifikationsudbyder';
$string['settings:mastery_classifier_provider_desc'] = 'Udbyder-id brugt til mestringklassifikatoren pr. omgang. Lad feltet stå tomt for at arve standardudbyderen for kunstig intelligens. Standarden <code>openai</code> parres med <code>gpt-4o-mini</code>-klassifikationsmodellen nedenfor — den billigste TIER 1-mulighed til struktureret-output-klassifikation (~220 $/md. besparelse ved 100.000 MAU ift. chattier). Når den er angivet, leverer rækken i Sammenligningsudbydere med dette udbyder-id API-nøgle, basis-URL og temperatur.';
$string['settings:premium_escalation_heading'] = 'Premium eskaleringstier (A.10)';
$string['settings:premium_escalation_heading_desc'] = 'Valgfri pr. omgang-routing til en premiummodel (Claude Opus 4.8 som standard) for prompts, hvor arbejdshest-chattieren tydeligt kæmper — typisk flertrinsmatte, CS og naturvidenskabelig ræsonnement. Fastlagt af 2026-06-09 A.10 bake-off: Opus 4.8 vandt 14,97/15 mod gpt-4o\'s 12,68/15 på svære prompts. To triggerveje: regex-match på brugermeddelelsen ELLER en kursus-tilladelsesliste, der eskalerer ved hver omgang. Slået fra som standard. Ved ~5 % eskalering forventet ~700 $/md. ved 100.000 Saylor MAU oven i det grundlæggende chatforbrug.';
$string['settings:premium_escalation_enabled'] = 'Aktivér premium eskaleringsrouting';
$string['settings:premium_escalation_enabled_desc'] = 'Når aktiveret kontrollerer pr.-omgang-routeren trigger-regex-listen og kursus-tilladelseslisten for hvert chat-kald; matchende omgange routes til premiumudbyderen. Falder tilbage til arbejdshestudbyderen, hvis premiumrækken mangler eller ikke kan instantieres. Admin-LLM-picker-tilsidesættelser vinder altid.';
$string['settings:premium_escalation_provider'] = 'Premiumudbyder';
$string['settings:premium_escalation_provider_desc'] = 'Udbyder-id til routing af premiumkald. Skal svare til en række i Sammenligningsudbydere (så API-nøgle, basis-URL og temperatur kommer fra det samme sted, administratorer allerede administrerer). Standard <code>claude</code>.';
$string['settings:premium_escalation_model'] = 'Premiummodel';
$string['settings:premium_escalation_model_desc'] = 'Modelnavn videregivet til premiumudbyderen. Standard <code>claude-opus-4-8</code> i henhold til A.10 bake-off-verdikten.';
$string['settings:premium_escalation_triggers'] = 'Premium trigger-regex';
$string['settings:premium_escalation_triggers_desc'] = 'Én PCRE-regex pr. linje (uden afgrænsere; der anvendes automatisk ufølsom skrifttype-matchning). Linjer der starter med # er kommentarer. Lad feltet stå tomt for at bruge det kurerede standardsæt fra A.10 bake-off (flertrinsstems-markører: „derive", „prove that", „step by step", LaTeX-matematik, afgrænsede kodeblokke, big-O, integraler, optimering osv.).';
$string['settings:premium_escalation_course_tags'] = 'Premium kursus-tilladelsesliste';
$string['settings:premium_escalation_course_tags_desc'] = 'Ét kursus-kortnavn eller idnumber-præfiks pr. linje. Alle omgange i et matchende kursus eskalerer automatisk uanset meddelelsesregex (brug til STEM-tunge kurser, hvor eskalering bør være standard). Matchning er ufølsom skrifttype-præfiks — „MATH" matcher MATH121, MATH205 osv.';
$string['settings:spend_cap_per_course_default'] = 'Standard pr.-kursus forbrugsloft (USD)';
$string['settings:spend_cap_per_course_default_desc'] = 'Defensivt loft anvendt på ethvert kursus, der ikke har sit eget pr.-kursus-forbrugsloft konfigureret. Angiv f.eks. <code>30</code> for at begrænse ethvert kursus\' månedlige forbrug til $30 uden at tilpasse de enkelte kurser. <code>0</code> = intet standardloft (kun site-dækkende og pr.-kursus-tilsidesætlofter gælder). Når et kursus passerer 80 % / 95 % / 100 % af dette loft, sender den eksisterende spend-guard-advarselspipeline administratornotifikationen (modtagerliste: <code>spend_notify_emails</code>, falder tilbage til webstedsadministratorer). Et specifikt kursus kan altid hæve sit eget loft ved at angive en højere pr.-kursus-tilsidesættelse.';
$string['settings:cost_anomaly_heading'] = 'Omkostningsanomalidetektor (v6.0)';
$string['settings:cost_anomaly_heading_desc'] = 'Daglig planlagt opgave (<code>cost_anomaly_check</code>), der sammenligner dagens websteds-dækkende SOLA-forbrug med den rullende 7-dages median. Sender en mail til modtagerlisten <code>spend_notify_emails</code> (falder tilbage til webstedsadministratorer), når dags dato overstiger den konfigurerede multiplikator × medianen. Opfanger tre fejltilstande, som de eksisterende 80 % / 95 % / 100 % forbrugslofttærskler overser: (1) løbsk kursus, hvor det absolutte loft ikke krydses, men ét kursus pludselig driver 10× sit sædvanlige volumen, (2) utilsigtet aktivering af premiumtier, (3) udbyder-fejlrouting. Slået fra som standard; det SOLA-interne ækvivalent til Redash-forespørgslen på <code>.drafts/sola-redash-cost-anomaly-2026-06-09.md</code>.';
$string['settings:cost_anomaly_enabled'] = 'Aktivér omkostningsanomalidetektor';
$string['settings:cost_anomaly_enabled_desc'] = 'Når aktiveret vurderer den daglige planlagte opgave dagens forbrug mod den rullende 7-dages median og sender en mail til administratorer ved anomali. De første 7 dage efter aktivering giver status <code>insufficient_history</code> (endnu intet historisk grundlag) og udsender aldrig en advarsel. Idempotent pr. dag: et flag i <code>config_plugins</code> forhindrer gentagne mails, hvis cron kører flere gange.';
$string['settings:cost_anomaly_multiplier'] = 'Anomalimultiplikator';
$string['settings:cost_anomaly_multiplier_desc'] = 'Dagens forbrug skal overstige denne multiplikator × 7-dages medianen for at udløse en advarsel. Standard <code>2.0</code>. Sænk til <code>1.5</code> for tidligere advarsler (flere falske positive ved tilmeldingsudbrud). Hæv til <code>3.0</code>, hvis Saylors forbrug er ujævnt nok til, at 2× toppe er rutinemæssige.';
$string['task:cost_anomaly_check'] = 'SOLA-omkostningsanomalikontrol (daglig)';

// v6.4.0 signed policy bundle strings (added 2026-06-11).
$string['settings:policy_bundle_heading'] = 'Signeret politikpakke (fjernbetjente adfærdsopdateringer)';
$string['settings:policy_bundle_heading_desc'] = 'Anvend adfærdsindstillinger (prompter, routing, eskaleringstriggere, RAG-justering, forbrugspolitik) fra en kryptografisk signeret JSON-fil uden kodeinstallation. En daglig planlagt opgave henter pakkens URL, verificerer dens Ed25519-signatur mod den nedenfor angivne offentlige nøgle og anvender indstillingerne kun, hvis alle nøgler er på den indbyggede tilladelsesliste, og pakkeversionen er nyere end den sidst anvendte. API-nøgler, URL\'er, webhooks og sikkerhedsindstillinger kan aldrig indstilles af en pakke. Opret og signer pakker med <code>admin/cli/policy_bundle_tool.php</code> (keygen, sign, verify, status, sync).';
$string['settings:policy_bundle_enabled'] = 'Aktivér synkronisering af politikpakke';
$string['settings:policy_bundle_enabled_desc'] = 'Når aktiveret henter den daglige opgave og anvender signerede pakker. Deaktiveret som standard. Deaktivering stopper alle synkroniseringer øjeblikkeligt; allerede anvendte indstillinger beholder deres værdier.';
$string['settings:policy_bundle_url'] = 'URL til politikpakke';
$string['settings:policy_bundle_url_desc'] = 'HTTPS URL til den signerede JSON-pakke (f.eks. et S3-objekt eller GitHub raw URL). URL\'en gennemgår den samme SSRF-validering som AI-udbyderslutpunkter; private netværk eller plain-http-servere kræver en post på SSRF\'s liste over betroede slutpunkter.';
$string['settings:policy_bundle_pubkey'] = 'Politikpakkens offentlige nøgle';
$string['settings:policy_bundle_pubkey_desc'] = 'Base64 Ed25519 offentlig nøgle til verificering af pakkesignaturer. Generér nøgleparret med <code>policy_bundle_tool.php --keygen</code>; den private nøgle forbliver hos pakkeforfatteren og må aldrig uploades nogen steder.';
$string['settings:policy_bundle_status'] = 'Seneste synkronisering';
$string['settings:policy_bundle_applied_version'] = 'anvendt version';
$string['task:policy_bundle_sync'] = 'SOLA signeret politikpakke-synkronisering';
$string['policy_bundle:invalid'] = 'Politikpakke afvist: {$a}';
